 1→import { motion } from "motion/react";
 2→import type { ReactNode } from "react";
 3→import styles from "./Button.module.scss";
 4→
 5→interface ButtonProps {
 6→  variant?: "primary" | "secondary" | "ghost";
 7→  size?: "sm" | "md" | "lg";
 8→  children: ReactNode;
 9→  className?: string;
10→  href?: string;
11→  disabled?: boolean;
12→  onClick?: () => void;
13→  type?: "button" | "submit" | "reset";
14→}
15→
16→export function Button({
17→  variant = "primary",
18→  size = "md",
19→  children,
20→  className,
21→  href,
22→  disabled,
23→  onClick,
24→  type = "button",
25→}: ButtonProps) {
26→  const classNames = [
27→    styles.button,
28→    styles[variant],
29→    styles[size],
30→    className,
31→  ]
32→    .filter(Boolean)
33→    .join(" ");
34→
35→  if (href) {
36→    return (
37→      <motion.a
38→        href={href}
39→        className={classNames}
40→        whileHover={{ scale: 1.02 }}
41→        whileTap={{ scale: 0.98 }}
42→      >
43→        {children}
44→      </motion.a>
45→    );
46→  }
47→
48→  return (
49→    <motion.button
50→      className={classNames}
51→      disabled={disabled}
52→      onClick={onClick}
53→      type={type}
54→      whileHover={{ scale: 1.02 }}
55→      whileTap={{ scale: 0.98 }}
56→    >
57→      {children}
58→    </motion.button>
59→  );
60→}
