 1→import { motion } from "motion/react";
 2→import type { Candidate } from "@rearden/types";
 3→import { SkillTag } from "@/components/SkillTag/SkillTag";
 4→import { ScoreBadge } from "@/components/ScoreBadge/ScoreBadge";
 5→import styles from "./CandidateCard.module.scss";
 6→
 7→interface CandidateCardProps {
 8→  candidate: Candidate;
 9→  score?: number;
10→  matchReason?: string;
11→  onClick?: () => void;
12→}
13→
14→export function CandidateCard({
15→  candidate,
16→  score,
17→  matchReason,
18→  onClick,
19→}: CandidateCardProps) {
20→  const displaySkills = candidate.skills.slice(0, 4);
21→
22→  return (
23→    <motion.div
24→      className={styles.card}
25→      whileHover={{ y: -4 }}
26→      onClick={onClick}
27→      role={onClick ? "button" : undefined}
28→      tabIndex={onClick ? 0 : undefined}
29→    >
30→      <div className={styles.thumbnail}>
31→        {candidate.thumbnailUrl ? (
32→          <img src={candidate.thumbnailUrl} alt={candidate.name} />
33→        ) : (
34→          <div className={styles.placeholder} />
35→        )}
36→        {score !== undefined && (
37→          <div className={styles.scoreBadge}>
38→            <ScoreBadge score={score} />
39→          </div>
40→        )}
41→      </div>
42→
43→      <div className={styles.content}>
44→        <h3 className={styles.name}>{candidate.name}</h3>
45→        <p className={styles.title}>{candidate.title}</p>
46→        <p className={styles.location}>{candidate.location}</p>
47→
48→        <div className={styles.skills}>
49→          {displaySkills.map((skill) => (
50→            <SkillTag key={skill} skill={skill} size="sm" />
51→          ))}
52→        </div>
53→
54→        {matchReason && (
55→          <p className={styles.matchReason}>{matchReason}</p>
56→        )}
57→      </div>
58→    </motion.div>
59→  );
60→}
