 1→import {
 2→  createContext,
 3→  useContext,
 4→  useEffect,
 5→  useState,
 6→  type ReactNode,
 7→} from "react";
 8→
 9→type Theme =
10→  | "y2k"
11→  | "purple-night"
12→  | "rearden-metal"
13→  | "steel-frost"
14→  | "forge"
15→  | "neon"
16→  | "daylight"
17→  | "bliss"
18→  | "aurora"
19→  | "meadow";
20→
21→interface ThemeContextValue {
22→  theme: Theme;
23→  setTheme: (theme: Theme) => void;
24→}
25→
26→const ThemeContext = createContext<ThemeContextValue | null>(null);
27→
28→const STORAGE_KEY = "rearden-theme";
29→
30→const THEMES: { value: Theme; label: string }[] = [
31→  { value: "y2k", label: "Y2K" },
32→  { value: "purple-night", label: "Purple Night" },
33→  { value: "rearden-metal", label: "Rearden Metal" },
34→  { value: "steel-frost", label: "Steel Frost" },
35→  { value: "forge", label: "Forge" },
36→  { value: "neon", label: "Neon Y2K" },
37→  { value: "daylight", label: "Daylight" },
38→  { value: "bliss", label: "Bliss" },
39→  { value: "aurora", label: "Aurora" },
40→  { value: "meadow", label: "Meadow" },
41→];
42→
43→const THEME_VALUES = new Set<string>(THEMES.map((t) => t.value));
44→
45→function getInitialTheme(): Theme {
46→  const stored = localStorage.getItem(STORAGE_KEY);
47→  if (stored && THEME_VALUES.has(stored)) return stored as Theme;
48→  return "y2k";
49→}
50→
51→export function ThemeProvider({ children }: { children: ReactNode }) {
52→  const [theme, setTheme] = useState<Theme>(getInitialTheme);
53→
54→  useEffect(() => {
55→    document.documentElement.setAttribute("data-theme", theme);
56→    localStorage.setItem(STORAGE_KEY, theme);
57→  }, [theme]);
58→
59→  return (
60→    <ThemeContext.Provider value={{ theme, setTheme }}>
61→      {children}
62→    </ThemeContext.Provider>
63→  );
64→}
65→
66→export function useTheme() {
67→  const ctx = useContext(ThemeContext);
68→  if (!ctx) throw new Error("useTheme must be used within ThemeProvider");
69→  return ctx;
70→}
71→
72→export { THEMES };
73→export type { Theme };
74→

