 41→            className={styles.subtitle}
 42→            initial={{ opacity: 0 }}
 43→            animate={{ opacity: 1 }}
 44→            transition={{ duration: 0.5, delay: 0.1 }}
 45→          >
 46→            {query
 47→              ? `${results.length} candidate${results.length !== 1 ? "s" : ""} found`
 48→              : "Use AI-powered search to find your perfect candidates"}
