## A2: Sound System

**Goal**: Subtle audio feedback on interactions. Uses Web Audio API (no external dependencies).

**Files modified: 4 | Files created: 3 | Total: 7**

### New file 1: `C:\Users\yakik\Documents\projects\rearden\apps\web\src\contexts\SoundContext.tsx`

SoundContext provides global sound state and a `playSound` function. Uses Web Audio API to synthesize short sounds rather than loading mp3 files (avoids needing external assets initially -- can be swapped for real sound files later).

```tsx
import { createContext, useContext, useState, useCallback, useRef, type ReactNode } from "react";

type SoundName = "click" | "hover" | "success" | "error" | "notify" | "navigate";

interface SoundContextValue {
  soundEnabled: boolean;
  toggleSound: () => void;
  playSound: (name: SoundName) => void;
}

const SoundContext = createContext<SoundContextValue | null>(null);

const STORAGE_KEY = "rearden-sound";

// Sound synthesis configurations
const SOUND_CONFIGS: Record<SoundName, { frequency: number; duration: number; type: OscillatorType; volume: number }> = {
  click:    { frequency: 800,  duration: 0.05, type: "sine",     volume: 0.15 },
  hover:    { frequency: 600,  duration: 0.03, type: "sine",     volume: 0.05 },
  success:  { frequency: 880,  duration: 0.15, type: "sine",     volume: 0.12 },
  error:    { frequency: 200,  duration: 0.2,  type: "sawtooth", volume: 0.1  },
  notify:   { frequency: 1200, duration: 0.1,  type: "sine",     volume: 0.12 },
  navigate: { frequency: 500,  duration: 0.06, type: "triangle", volume: 0.08 },
};

export function SoundProvider({ children }: { children: ReactNode }) {
  const [soundEnabled, setSoundEnabled] = useState(() => {
    const stored = localStorage.getItem(STORAGE_KEY);
    return stored !== "false"; // enabled by default
  });
  const audioCtxRef = useRef<AudioContext | null>(null);

  const getAudioContext = useCallback(() => {
    if (!audioCtxRef.current) {
      audioCtxRef.current = new AudioContext();
    }
    return audioCtxRef.current;
  }, []);

  const playSound = useCallback((name: SoundName) => {
    if (!soundEnabled) return;
    const config = SOUND_CONFIGS[name];
    if (!config) return;

    try {
      const ctx = getAudioContext();
      const oscillator = ctx.createOscillator();
      const gainNode = ctx.createGain();

      oscillator.type = config.type;
      oscillator.frequency.setValueAtTime(config.frequency, ctx.currentTime);

      gainNode.gain.setValueAtTime(config.volume, ctx.currentTime);
      gainNode.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + config.duration);

      oscillator.connect(gainNode);
      gainNode.connect(ctx.destination);

      oscillator.start(ctx.currentTime);
      oscillator.stop(ctx.currentTime + config.duration);
    } catch {
      // Silently fail if audio not available
    }
  }, [soundEnabled, getAudioContext]);

  const toggleSound = useCallback(() => {
    setSoundEnabled((prev) => {
      const next = !prev;
      localStorage.setItem(STORAGE_KEY, String(next));
      return next;
    });
  }, []);

  return (
    <SoundContext.Provider value={{ soundEnabled, toggleSound, playSound }}>
      {children}
    </SoundContext.Provider>
  );
}

export function useSound() {
  const ctx = useContext(SoundContext);
  if (!ctx) throw new Error("useSound must be used within SoundProvider");
  return ctx;
}
```

### New file 2: `C:\Users\yakik\Documents\projects\rearden\apps\web\src\hooks\useSound.ts`

