### New file 1: `C:\Users\yakik\Documents\projects\rearden\apps\web\src\contexts\SidebarContext.tsx`

Manages sidebar open/closed state, needed for mobile drawer behavior:

```tsx
import { createContext, useContext, useState, useCallback, type ReactNode } from "react";

interface SidebarContextValue {
  sidebarOpen: boolean;
  toggleSidebar: () => void;
  closeSidebar: () => void;
}

const SidebarContext = createContext<SidebarContextValue | null>(null);

export function SidebarProvider({ children }: { children: ReactNode }) {
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const toggleSidebar = useCallback(() => setSidebarOpen((prev) => !prev), []);
  const closeSidebar = useCallback(() => setSidebarOpen(false), []);

  return (
    <SidebarContext.Provider value={{ sidebarOpen, toggleSidebar, closeSidebar }}>
      {children}
    </SidebarContext.Provider>
  );
}

export function useSidebar() {
  const ctx = useContext(SidebarContext);
  if (!ctx) throw new Error("useSidebar must be used within SidebarProvider");
  return ctx;
}
```

On desktop (>1024px), the sidebar is always visible and this context controls nothing. On tablet/mobile, `sidebarOpen` controls the drawer visibility.

