### New file 2: `C:\Users\yakik\Documents\projects\rearden\apps\web\src\contexts\NotificationContext.tsx`

```tsx
import {
  createContext, useContext, useState, useCallback, useEffect, type ReactNode
} from "react";
import {
  MOCK_NOTIFICATIONS, INCOMING_NOTIFICATIONS,
  type Notification
} from "@/data/mockNotifications";

interface NotificationContextValue {
  notifications: Notification[];
  unreadCount: number;
  dismiss: (id: string) => void;
  markRead: (id: string) => void;
  markAllRead: () => void;
}

const NotificationContext = createContext<NotificationContextValue | null>(null);

export function NotificationProvider({ children }: { children: ReactNode }) {
  const [notifications, setNotifications] = useState<Notification[]>(MOCK_NOTIFICATIONS);

  const unreadCount = notifications.filter((n) => !n.read).length;

  const dismiss = useCallback((id: string) => {
    setNotifications((prev) => prev.filter((n) => n.id !== id));
  }, []);

  const markRead = useCallback((id: string) => {
    setNotifications((prev) =>
      prev.map((n) => (n.id === id ? { ...n, read: true } : n))
    );
  }, []);

  const markAllRead = useCallback(() => {
    setNotifications((prev) => prev.map((n) => ({ ...n, read: true })));
  }, []);

  // Simulate incoming notifications
  useEffect(() => {
    const timers = INCOMING_NOTIFICATIONS.map((notification, i) =>
      setTimeout(() => {
        setNotifications((prev) => [
          { ...notification, timestamp: new Date() },
          ...prev,
        ]);
        // Sound integration: dispatch custom event for SoundContext
      }, (i + 1) * 15_000) // Every 15 seconds
    );

    return () => timers.forEach(clearTimeout);
  }, []);

  return (
    <NotificationContext.Provider value={{ notifications, unreadCount, dismiss, markRead, markAllRead }}>
      {children}
    </NotificationContext.Provider>
  );
}

export function useNotifications() {
  const ctx = useContext(NotificationContext);
  if (!ctx) throw new Error("useNotifications must be used within NotificationProvider");
  return ctx;
}
```

