import { useNavigate } from "react-router-dom";
import { motion } from "motion/react";
import { useNotifications } from "@/contexts/NotificationContext";
import { useSound } from "@/hooks/useSound";
import type { Notification } from "@/data/mockNotifications";
import styles from "./NotificationItem.module.scss";

const TYPE_ICONS: Record<string, string> = {
  new_candidate: "M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z",
  interview_scheduled: "M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z",
  message_received: "M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z",
  status_change: "M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z",
};

interface NotificationItemProps {
  notification: Notification;
}

function timeAgo(date: Date): string {
  const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
  if (seconds < 60) return "Just now";
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m ago`;
  if (seconds < 86400) return `${Math.floor(seconds / 3600)}h ago`;
  return `${Math.floor(seconds / 86400)}d ago`;
}

export function NotificationItem({ notification }: NotificationItemProps) {
  const navigate = useNavigate();
  const { dismiss, markRead } = useNotifications();
  const { playSound } = useSound();

  const handleAction = () => {
    playSound("click");
    markRead(notification.id);
    if (notification.actionRoute) {
      navigate(notification.actionRoute);
    }
  };

  const handleDismiss = () => {
    playSound("click");
    dismiss(notification.id);
  };

  return (
    <motion.div
      className={`${styles.item} ${notification.read ? "" : styles.unread}`}
      whileTap={{ scale: 0.98 }}
      transition={{ type: "spring", stiffness: 400, damping: 25 }}
    >
      <div className={styles.icon}>
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <path d={TYPE_ICONS[notification.type]} />
        </svg>
      </div>
      <div className={styles.content}>
        <p className={styles.message}>{notification.message}</p>
        <span className={styles.time}>{timeAgo(notification.timestamp)}</span>
      </div>
      <div className={styles.actions}>
        {notification.actionLabel && (
          <button className={styles.actionBtn} onClick={handleAction}>
            {notification.actionLabel}
          </button>
        )}
        <button className={styles.dismissBtn} onClick={handleDismiss} aria-label="Dismiss">
          {/* X icon */}
        </button>
      </div>
    </motion.div>
  );
}
