### New file 2: `C:\Users\yakik\Documents\projects\rearden\apps\web\src\contexts\ChatContext.tsx`

```tsx
import {
  createContext, useContext, useState, useCallback, type ReactNode
} from "react";
import {
  MOCK_CONVERSATIONS,
  type Conversation, type ChatMessage
} from "@/data/mockConversations";

interface ChatContextValue {
  conversations: Conversation[];
  activeConversationId: string | null;
  activeConversation: Conversation | null;
  totalUnread: number;
  openConversation: (id: string) => void;
  openConversationByCandidate: (candidateId: string) => void;
  closeConversation: () => void;
  sendMessage: (text: string) => void;
  startConversation: (candidateId: string, candidateName: string, candidateTitle: string) => void;
}

const ChatContext = createContext<ChatContextValue | null>(null);

export function ChatProvider({ children }: { children: ReactNode }) {
  const [conversations, setConversations] = useState<Conversation[]>(MOCK_CONVERSATIONS);
  const [activeConversationId, setActiveConversationId] = useState<string | null>(null);

  const activeConversation = conversations.find((c) => c.id === activeConversationId) ?? null;
  const totalUnread = conversations.reduce((sum, c) => sum + c.unreadCount, 0);

  const openConversation = useCallback((id: string) => {
    setActiveConversationId(id);
    // Mark as read
    setConversations((prev) =>
      prev.map((c) => (c.id === id ? { ...c, unreadCount: 0 } : c))
    );
  }, []);

  const openConversationByCandidate = useCallback((candidateId: string) => {
    const conv = conversations.find((c) => c.candidateId === candidateId);
    if (conv) {
      openConversation(conv.id);
    }
  }, [conversations, openConversation]);

  const closeConversation = useCallback(() => {
    setActiveConversationId(null);
  }, []);

  const sendMessage = useCallback((text: string) => {
    if (!activeConversationId || !text.trim()) return;

    const newMessage: ChatMessage = {
      id: `m-${Date.now()}`,
      senderId: "me",
      text: text.trim(),
      timestamp: new Date(),
    };

    setConversations((prev) =>
      prev.map((c) =>
        c.id === activeConversationId
          ? { ...c, messages: [...c.messages, newMessage] }
          : c
      )
    );
  }, [activeConversationId]);

  const startConversation = useCallback((candidateId: string, candidateName: string, candidateTitle: string) => {
    const existing = conversations.find((c) => c.candidateId === candidateId);
    if (existing) {
      openConversation(existing.id);
      return;
    }

    const newConv: Conversation = {
      id: `conv-${Date.now()}`,
      candidateId,
      candidateName,
      candidateTitle,
      messages: [],
      unreadCount: 0,
    };

    setConversations((prev) => [newConv, ...prev]);
    setActiveConversationId(newConv.id);
  }, [conversations, openConversation]);

  return (
    <ChatContext.Provider value={{
      conversations, activeConversationId, activeConversation, totalUnread,
      openConversation, openConversationByCandidate, closeConversation, sendMessage, startConversation,
    }}>
      {children}
    </ChatContext.Provider>
  );
}

export function useChat() {
  const ctx = useContext(ChatContext);
  if (!ctx) throw new Error("useChat must be used within ChatProvider");
  return ctx;
}
