import { motion } from "motion/react";
import { useChat } from "@/contexts/ChatContext";
import { useSound } from "@/hooks/useSound";
import styles from "./ConversationList.module.scss";

function timeAgo(date: Date): string {
  const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
  if (seconds < 60) return "now";
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m`;
  if (seconds < 86400) return `${Math.floor(seconds / 3600)}h`;
  return `${Math.floor(seconds / 86400)}d`;
}

export function ConversationList() {
  const { conversations, openConversation } = useChat();
  const { playSound } = useSound();

  return (
    <div className={styles.list}>
      {conversations.map((conv) => {
        const lastMessage = conv.messages[conv.messages.length - 1];

        return (
          <motion.button
            key={conv.id}
            className={`${styles.item} ${conv.unreadCount > 0 ? styles.unread : ""}`}
            onClick={() => { playSound("click"); openConversation(conv.id); }}
            whileTap={{ scale: 0.97 }}
            transition={{ type: "spring", stiffness: 400, damping: 25 }}
          >
            <div className={styles.avatar}>
              {conv.candidateName.charAt(0)}
            </div>
            <div className={styles.content}>
              <div className={styles.topRow}>
                <span className={styles.name}>{conv.candidateName}</span>
                {lastMessage && (
                  <span className={styles.time}>{timeAgo(lastMessage.timestamp)}</span>
                )}
              </div>
              {lastMessage && (
                <p className={styles.preview}>
                  {lastMessage.senderId === "me" ? "You: " : ""}
                  {lastMessage.text}
                </p>
              )}
            </div>
            {conv.unreadCount > 0 && (
              <span className={styles.badge}>{conv.unreadCount}</span>
            )}
          </motion.button>
        );
      })}
    </div>
  );
}
